                                        border: "none",
                                        background: "#eff6ff",
                                        color: "#1d4ed8",
                                        borderRadius: "8px",
                                        padding: "4px 8px",
                                        fontSize: "0.75rem",
                                        fontWeight: "800",
                                        display: "inline-flex",
                                        alignItems: "center",
                                        gap: "4px",
