                              setPaymentMethod(method);
                              if (method === "cash") {
                                setPaymentAmountReceived(total.toFixed(2));
                              } else {
                                setPaymentAmountReceived("");
                              }
                              if (method === "transfer") {
                                openNumpad(paymentCardLastFour || "", 0, "card_digits");
                              }
